require_once( 'view/QuickFormIncludes.php' );;
require_once( 'view/TabbedPages.php' );;

class bondrate_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('bondrate page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$idbondrate = $fs->addElement('text', 'idbondrate', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
;
		$calendaryear = $fs->addElement('text', 'calendaryear', array('size' => 19, 'maxlength' => 19) )
			->setLabel( 'Calendar Year' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'calendaryear Field Required' );
		$bondrate = $fs->addElement('text', 'bondrate', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Bond Rate' )
			->addRule('required', 'bondrate Field Required' );
	}
}
